import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SecureCommandExecutionExample {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String userInput = reader.readLine();

            // Safely execute the command using ProcessBuilder
            ProcessBuilder processBuilder = new ProcessBuilder();
            processBuilder.command("sh", "-c", userInput); // Use shell to run the command

            Process process = processBuilder.start();
            int exitCode = process.waitFor();

            if (exitCode == 0) {
                System.out.println("Command executed successfully.");
            } else {
                System.out.println("Error executing the command.");
            }
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }
}

